//-------------------------------------------------------------------------
// 선택된 오더 유형별 화면 설정을 변경한다.
//-------------------------------------------------------------------------
scwin.f_setDisplayOdrKndCd = function (odrKndCd) {
  switch (odrKndCd) {
    case DsConstants.ODR_KND_CD_IMP_CVSSL_BULK_ODR: // 수입본선벌크오더
    case DsConstants.ODR_KND_CD_IMP_GNRL_BULK_ODR: // 수입일반벌크오더
    case DsConstants.ODR_KND_CD_EXP_CVSSL_BULK_ODR: // 수출본선벌크오더
    case DsConstants.ODR_KND_CD_EXP_GNRL_BULK_ODR:
      // 수출일반벌크오더
      // 그리드 항목 설정
      gr_odrWrkPathStpDetail.setColumnVisible("vsslCdPortcnt", false);
      break;
    default:
      // 기타 벌크 오더 + 내수 오더
      // 그리드 항목 설정
      gr_odrWrkPathStpDetail.setColumnVisible("vsslCdPortcnt", false);
      break;
  }
};

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
  scwin.odrNo = $c.data.getParameter($p, "odrNo") == null ? "" : $c.data.getParameter($p, "odrNo");
  scwin.type = $c.data.getParameter($p, "type") == null ? "" : $c.data.getParameter($p, "type");
};

//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  // 초기화
  scwin.f_defaultValue();
  dma_lobranQueryCondition.set("lobranCd", scwin.wrkLobranCd);
  dma_lobranQueryCondition.set("lobranClsCd", "T");
  dma_lobranQueryCondition.set("deptmentCd", DsConstants.TRANS_DEPARTMENT);
  dma_lobranQueryCondition.set("useYn", DsConstants.YN_YES);
  scwin.lc_odrSearchGubun_onviewchange();
  if (scwin.odrNo != "") {
    lc_odrSearchGubun.setSelectedIndex(1);
    ed_odrNo.setValue(scwin.odrNo);
    dscommon.cf_HideObject([udc_odrDt]); // 오더기간 조회조건
    dscommon.cf_ShowObject([ed_odrNo]); // 출발일자 조회조건

    // 오더기간, 출발일자 검색조건 초기화                       
    ica_odrDtFrom.setValue("");
    ica_odrDtTo.setValue("");
    scwin.f_Retrieve();
  }
};

