//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if (lc_odrSearchGubun.getSelectedIndex() == 0) {
    // 오더기간 From - To 입력 확인
    let ret = await $c.gus.cfValidate($p, [ica_odrDtFrom, ica_odrDtTo]);
    if (!ret) {
      return;
    }

    // 오더기간 범위 확인
    if (!(await $c.gus.cfIsAfterDate($p, ica_odrDtFrom.getValue(), ica_odrDtTo.getValue()))) {
      await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_048, "오더기간 From", "오더기간 To"));
      ica_odrDtFrom.focus();
      return false;
    }
    let diffObj = await $c.gus.cfDifferBetween($p, ica_odrDtFrom.getValue(), ica_odrDtTo.getValue());
    // 오더기간이 1달 이상인경우 확인

    if (diffObj.year > 0 || diffObj.month > 0) {
      if (!(await $c.win.confirm($p, "오더기간 이 1개월이 넘습니다.조회하시겠습니까?"))) {
        ica_odrDtFrom.focus();
        return false;
      }
    }
  } else {
    let ret = await $c.gus.cfValidate($p, [ed_odrNo]);
    if (!ret) return;
  }

  //if(cfValidate(ed_odrNo)){
  let odrNo = ed_odrNo.getValue().replace(/\s*$/, '');
  let odrDtFrom = ica_odrDtFrom.getValue().replace(/\s*$/, '');
  let odrDtTo = ica_odrDtTo.getValue().replace(/\s*$/, '');
  $c.gus.cfDisableObjects($p, [btnInsertRow, btnDeleteRow, btnUndoMark, btn_edit, btn_save]);
  $c.gus.cfEnableBtnOnly($p, [btn_save]);
  ds_odrCommWrkPath.removeAll();
  ds_ctrtWrkPath.removeAll();
  ds_odrWrkPathStep.removeAll();
  ds_ctrtWrkPathStep.removeAll();

  // 그리드 총건수 초기화
  totalRows.setValue(0);
  totalRows2.setValue(0);
  ds_odrWrkPathStepDetail.removeAll();
  ds_odrWrkPathStepDetailTemp.removeAll();

  // 작업장구분 Lokkup DataSet Setting
  scwin.f_wrkPlClsCd();

  //작업단계 LookUp DataSet Setting
  scwin.f_LkStepNo();
  dma_orderSearch.set("odrNo", odrNo);
  dma_orderSearch.set("odrDtFrom", odrDtFrom);
  dma_orderSearch.set("odrDtTo", odrDtTo);
  $c.sbm.execute($p, sbm_retrieve);
  //} 
};

