//-------------------------------------------------------------------------
// 선택된 작업경로에 대한 작업 단계 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveWorkStep = async function () {
  if (dma_searchWrkStep.get("ctrtWrkPathSeq") == 0) {
    return;
  }

  // 선택된 작업경로별 작업단계 조회
  let e = await $c.sbm.execute($p, sbm_searchWorkStep);
  scwin.sbm_searchWorkStep_submitdone(e);
};

//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 삽입 : 첫번째열을 선택한 경우 해당열 아래에 행삽입 후 이전 작업단계 정보 복사
//-------------------------------------------------------------------------
scwin.f_InsertRow = async function () {
  let rowPos = ds_odrWrkPathStepDetail.getRowPosition();
  let v_tempSeq = parseInt(ds_odrWrkPathStepDetail.getCellData(rowPos, "odrWrkStpSeq") / 10) * 10;
  if (scwin.f_checkOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq)) {
    // 선택된 행 아래에 새로운 행 삽입
    let newRow = ds_odrWrkPathStepDetail.insertRow(rowPos + 1);
    gr_odrWrkPathStpDetail.setFocusedCell(newRow, "odrWrkStpSeq");
    scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, rowPos, newRow); // Note: original code used rowPosition-1, rowPosition after insert

    // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
    scwin.f_checkWorkStepEditMode(newRow);
  } else {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_055, ["작업단계"])); //작업단계을(를) 확인하여 주십시오
    return;
  }
};

//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 추가 후 이전 작업단계정보 복사
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
  let rowPos = ds_odrWrkPathStepDetail.getRowPosition();
  let v_tempSeq = parseInt(ds_odrWrkPathStepDetail.getCellData(rowPos, "odrWrkStpSeq") / 10) * 10;
  let newRow = rowPos;
  if (scwin.f_checkOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq)) {
    newRow = ds_odrWrkPathStepDetail.insertRow();
  }
  scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, newRow - 1, newRow);

  // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
  scwin.f_checkWorkStepEditMode(newRow);
};

//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = function () {
  let rowPos = ds_odrWrkPathStepDetail.getRowPosition();
  let colPos = gr_odrWrkPathStpDetail.getFocusedColumnIndex();
  if (ds_odrWrkPathStepDetail.getRowStatus(rowPos) == "C") {
    ds_odrWrkPathStepDetail.removeRow(rowPos);
    gr_odrWrkPathStpDetail.setFocusedCell(rowPos, "odrWrkStpSeq");
  } else {
    ds_odrWrkPathStepDetail.deleteRow(rowPos);
    gr_odrWrkPathStpDetail.setFocusedCell(rowPos, colPos);
  }

  // 삭제 후 포커스 재조정
  let newPos = ds_odrWrkPathStepDetail.getRowPosition();
  if (newPos >= 0) {
    let v_tempSeq = parseInt(ds_odrWrkPathStepDetail.getCellData(newPos, "odrWrkStpSeq") / 10) * 10;
    scwin.f_refreshOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq);

    // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
    scwin.f_checkWorkStepEditMode(newPos);
  }
};

//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 작업 취소
//-------------------------------------------------------------------------
scwin.f_UndoRow = function () {
  let rowPos = ds_odrWrkPathStepDetail.getRowPosition();
  $c.data.undoRow($p, ds_odrWrkPathStepDetail, rowPos);
  let v_tempSeq = parseInt(ds_odrWrkPathStepDetail.getCellData(rowPos, "odrWrkStpSeq") / 10) * 10;
  scwin.f_refreshOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq);

  // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
  scwin.f_checkWorkStepEditMode(rowPos);
};

//-------------------------------------------------------------------------
// 선택된 DATASET에 ROW 복사 ( 대상 DataSet, 원본 Row, 대상 Row )
//-------------------------------------------------------------------------
scwin.f_CopyDataRow = function (dataObject, sourceRow, targetRow) {
  let v_odrWrkStpSeq = dataObject.getCellData(sourceRow, "odrWrkStpSeq");
  let v_tempSeq = parseInt(v_odrWrkStpSeq / 10) * 10;
  let colId = "";
  for (let i = 0; i < dataObject.getColumnCount(); i++) {
    colId = dataObject.getColumnID(i);
    if (colId == "odrWrkStpSeq") {
      dataObject.setCellData(targetRow, colId, parseInt(dataObject.getCellData(sourceRow, colId)) + 1);
    } else if (colId == "wrkPlClsCd" || colId == "wrkStpCd" || colId == "dptWrkPlCd" || colId == "dptWrkPlNm" || colId == "arvWrkPlCd" || colId == "arvWrkPlNm" || colId == "wrkLobranCd" || colId == "wrkLobranNm" || colId == "wrkStDt" || colId == "wrkStHh" || colId == "wrkEndDt" || colId == "wrkEndHh" || colId == "internalSellLodeptCd" || colId == "internalSellLodeptNm" || colId == "bizDomCd" || colId == "completeYn") {
      //dataObject.setCellData(targetRow, colId, SdConstants.SELPCH_ITEM_CD_NOSELL); 
    } else if (colId == "selpchItemCd") {
      dataObject.setCellData(targetRow, colId, SdConstants.SELPCH_ITEM_CD_NOSELL);
    } else if (colId == "selpchItemNm") {
      dataObject.setCellData(targetRow, colId, "무매출");
    } else {
      dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
    }
  }
  scwin.f_refreshOdrWrkStpSeq(dataObject, v_tempSeq);
};

//-------------------------------------------------------------------------
// 선택된 DATASET에 오더 작업단계 추가 가능 확인
//-------------------------------------------------------------------------
scwin.f_checkOdrWrkStpSeq = function (dataObject, v_tempSeq) {
  for (let j = 0; j < dataObject.getRowCount(); j++) {
    let v_compSeq = dataObject.getCellData(j, "odrWrkStpSeq") - v_tempSeq;
    if (parseInt(dataObject.getCellData(j, "odrWrkStpSeq") / 10) * 10 == v_tempSeq && v_compSeq >= 9) {
      return false;
    }
  }
  return true;
};

//-------------------------------------------------------------------------
// 선택된 DATASET에 오더 작업단계순번 재정의
//-------------------------------------------------------------------------
scwin.f_refreshOdrWrkStpSeq = function (dataObject, v_tempSeq) {
  // 오더작업단계순번 재정의
  for (let j = 0; j < dataObject.getRowCount(); j++) {
    let v_compSeq = dataObject.getCellData(j, "odrWrkStpSeq") - v_tempSeq;
    if (dataObject.getCellData(j, "odrWrkStpSeq") > v_tempSeq && v_compSeq > 0 && v_compSeq < 10) {
      if (j > 0) {
        dataObject.setCellData(j, "odrWrkStpSeq", parseInt(dataObject.getCellData(j - 1, "odrWrkStpSeq")) + 1);
      }
    }
  }
};
