//-------------------------------------------------------------------------
// 작업장 정보를 조회한다.
// row : 데이터셋의 Row
// pCode : 화면에서의 ??? Code Element의	Value
// pBizDomCd : 화면에서의 ??? Name Element의	Value
// pClose : 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
// pAllSearch : 전체검색허용여부	("F")
//-------------------------------------------------------------------------
scwin.f_setWorkPlaceLobranCd = async function (pCode, pName, pBizDomCd, pWrkPlClsCd, flag, row) {
  let pClose = "T";
  let pAllSearch = "F";
  let pNoDataCloseTF = "T";
  scwin.row = row;
  // 조회조건이 아닌경우 종료
  if ($c.gus.cfIsNull($p, pCode) && $c.gus.cfIsNull($p, pBizDomCd)) {
    return false;
  }
  let pWhere = pWrkPlClsCd + "," + pBizDomCd;
  let rtnList = await udc_workPlaceLobranCd.cfCommonPopUpAsync('retrieveWorkPlaceLobranCd_tpro', pCode // 화면에서의 ??? Code Element의	Value
  , pName // 화면에서의 ??? Name Element의	Value
  , pClose // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  , null // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  , null // Title순서	
  , null // 보여주는 각 컬럼들의 폭	
  , null // 컬럼중에서 숨기는	컬럼 지정	
  , pWhere // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  , null // POP-UP뛰을때 원도우의	사용자 정의	폭
  , null // POP-UP뛰을때 우도우의	사용자 정의	높이	
  , null // 윈도우 위치 Y좌표	
  , null // 윈도우 위치 X좌표
  , null // 중복체크여부	("F")
  , pAllSearch // 전체검색허용여부	("F")
  , "작업장,작업장코드/명" // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  , pNoDataCloseTF // Data건수가 0건일때 Window를 뛰우지 않음 리턴 : "N/A" 또는 null
  , null);
  return rtnList;
};

//-------------------------------------------------------------------------
// 품명별 실적 생성여부 확인 - 모든 품명의 실적이 생성된 경우 수정할 수 없음.
//-------------------------------------------------------------------------
scwin.f_chkCommodityWorkPath = function () {
  let chkWorkPath = true;
  for (let i = 0; i < ds_odrCommWrkPath.getRowCount(); i++) {
    if ($c.gus.cfIsNull($p, ds_odrCommWrkPath.getCellData(i, "wrkRsltsNo"))) {
      chkWorkPath = false;
    }
  }
  if (chkWorkPath) {
    $c.gus.cfDisableBtnOnly($p, [btn_edit]);
  } else {
    $c.gus.cfEnableBtnOnly($p, [btn_edit]);
  }
};

//-------------------------------------------------------------------------
// 선택된 컨테이너 작업경로 정보를 임시 데이터셋에 복사한다.
//-------------------------------------------------------------------------
scwin.f_CopyDataSetOdrCommWrkPath = function (ds1, ds2) {
  let row = ds1.getRowPosition();
  if (ds1.getRowStatus(row) != "D") {
    // RowStatus 가 Delete 가 아닌 경우
    ds2.removeAll();
    $c.gus.cfCopyDataSetHeader($p, ds1, ds2);
    let newRow = ds2.insertRow();
    for (let j = 0; j < ds1.getTotalCol(); j++) {
      ds2.setCellData(newRow, ds1.getColumnID(j), ds1.getCellData(row, ds1.getColumnID(j)));
    }
  }
};
scwin.f_RetrieveWorkStepReUse = async function () {
  let copyTempDataSet = false;
  let row = scwin.hid_rowNo;
  scwin.ds_odrWrkPathStepDetail_OnFilter();
  if (ds_odrCommWrkPath.getCellData(row, "ctrtWrkPathSeq") > 0) {
    if (ds_odrWrkPathStepDetail.getRowCount() > 0) {
      // 이미 작업단계가 존재함.
    } else {
      // 작업단계 검색 조건 설정
      dma_searchWrkStep.set("odrNo", ds_odrCommWrkPath.getCellData(row, "odrNo"));
      dma_searchWrkStep.set("commSeq", ds_odrCommWrkPath.getCellData(row, "commSeq"));
      dma_searchWrkStep.set("odrWrkPathSeq", ds_odrCommWrkPath.getCellData(row, "odrWrkPathSeq"));
      dma_searchWrkStep.set("ctrtNo", ds_odrCommWrkPath.getCellData(row, "ctrtNo"));
      dma_searchWrkStep.set("ctrtWrkPathSeq", ds_odrCommWrkPath.getCellData(row, "ctrtWrkPathSeq"));
      scwin.f_RetrieveWorkStep();
    }
    totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount());
  }
  if (row >= 0 && btn_edit.getDisabled() && !btn_save.getDisabled()) {
    if (scwin.f_chkResultsConfirmationCommodity(row)) {
      scwin.gr_odrCommWrkPath_setGridReadOnly(true);
      scwin.gr_odrWrkPathStpDetail_setGridReadOnly(true);
      $c.gus.cfDisableBtnOnly($p, [btnInsertRow, btnDeleteRow, btnUndoMark, btn_edit, btn_save]);
    } else {
      scwin.gr_odrCommWrkPath_setGridReadOnly(false);
      scwin.gr_odrWrkPathStpDetail_setGridReadOnly(false);
      $c.gus.cfEnableBtnOnly($p, [btnInsertRow, btnDeleteRow, btnUndoMark]);
    }
  }
  scwin.f_checkWorkStepEditMode();
  scwin.wrkLobranCd = scwin.lobranCd; // 작업점소코드
  scwin.wrkLobranNm = scwin.lobranNm; // 작업점소명

  // 사용자 040239 (채태종) 의 경우 운송 부서를 4A5(인천제강운송)으로 설정
  if (scwin.memJson.userId == "040239") {
    scwin.internalSellLodeptCd = "4A5";
    scwin.internalSellLodeptNm = "인천제강운송";
  } else {
    scwin.internalSellLodeptCd = ds_lobran.getCellData(ds_lobran.getRowPosition(), "lobranCd"); // 운송부서코드
    scwin.internalSellLodeptNm = ds_lobran.getCellData(ds_lobran.getRowPosition(), "lobranNm"); // 운송부서명
  }
  scwin.wrkLobranCdRow = 0; // 작업점소 설정 ROW 초기화
};
