scwin.ds_odrWrkPathStepDetail_OnFilter = function (row) {
  let v_odrNo = "";
  let v_commSeq = 0;
  let v_wrkPathSeq = 0;
  let v_odrWrkPathSeq = 0;
  let v_ctrtWrkPathSeq = 0;
  let chkFilter = scwin.hid_chkUseFilter;
  ds_LkStepNo.removeColumnFilterAll();
  ds_odrWrkPathStepDetail.removeColumnFilterAll();
  if (chkFilter) {
    // Filter 적용을 위한 값 
    if (ds_odrCommWrkPath.getRowPosition() >= 0) {
      v_odrNo = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "odrNo");
      v_commSeq = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "commSeq");
      v_odrWrkPathSeq = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "odrWrkPathSeq");
      v_ctrtWrkPathSeq = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "ctrtWrkPathSeq");
    }

    // 필터 적용
    $c.data.dataListFilter($p, ds_odrWrkPathStepDetail, "odrNo == '" + v_odrNo + "'" + " && commSeq == '" + v_commSeq + "'" + " && odrWrkPathSeq == '" + v_odrWrkPathSeq + "'" + " && ctrtWrkPathSeq == '" + v_ctrtWrkPathSeq + "'");
  }
};
scwin.ds_odrWrkPathStepDetailTemp_OnFilter = function (row) {
  let v_ctrtWrkPathSeq = 0;
  ds_odrWrkPathStepDetailTemp.removeColumnFilterAll();

  // Filter 적용을 위한 값
  if (ds_odrCommWrkPath.getRowPosition() >= 0) {
    v_ctrtWrkPathSeq = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "ctrtWrkPathSeq");
  }

  // 필터 적용
  $c.data.dataListFilter($p, ds_odrWrkPathStepDetailTemp, "ctrtWrkPathSeq == '" + v_ctrtWrkPathSeq + "'");
};
scwin.ds_LkStepNo_OnFilter = function (row) {
  if (ds_odrWrkPathStepDetail.getRowCount() > 0) {
    let v_wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim();
    let v_fltrCd1 = "";

    // 작업장구분 코드로 FLTR_CD_1 값 조회	
    if (v_wrkPlClsCd != "") {
      for (let i = 0; i < ds_wrkPlClsCd.getRowCount(); i++) {
        if (v_wrkPlClsCd == ds_wrkPlClsCd.getCellData(i, "cd")) {
          v_fltrCd1 = ds_wrkPlClsCd.getCellData(i, "fltrCd1");
        }
      }
    } else {
      v_fltrCd1 = "";
    }
    let hidVal = "";
    if (ds_odrWrkPathStepDetail.getRowCount() > 0) {
      if (v_fltrCd1 == "02") {
        // 하역 (작업단계코드 : 01)
        hidVal = "01";
      } else if (v_fltrCd1 != "02" && v_fltrCd1 != "") {
        // 본관,포장 (작업단계코드 : 03,04)
        hidVal = "03";
      } else {
        // 운송 (작업단계코드 : 02)
        hidVal = "02";
      }
      ds_LkStepNo.removeColumnFilterAll();
      $c.data.dataListFilter($p, ds_LkStepNo, "topWrkStpCd == '" + hidVal + "'");
    }
  }
};
scwin.gr_odrCommWrkPathNmChange = function (row) {
  let copyTempDataSet = false;
  scwin.hid_rowNo = row;
  let colId = gr_odrCommWrkPath.getFocusedColumnID();
  if (colId == "ctrtWrkPathNm") {
    // 이미 조회된 작업단계인지 확인
    scwin.ds_odrWrkPathStepDetail_OnFilter(row);
    if (ds_odrCommWrkPath.getCellData(row, "ctrtWrkPathSeq") > 0) {
      if (ds_odrWrkPathStepDetail.getRowCount() > 0) {} else {
        // 임시데이터셋에 존재하는 작업경로 정보와 동일한 정보인지 확인
        // 해당컨테이너의 출발작업장,도착작업장,F/E 가 모두 동일한 경우 임시 데이터셋에 저장된 작업단계를 복사한다.
        if (ds_odrCommWrkPathTemp.getRowCount() > 0) {
          if (ds_odrCommWrkPath.getCellData(row, "dptWrkPlCd") == ds_odrCommWrkPathTemp.getCellData(ds_odrCommWrkPathTemp.getRowPosition(), "dptWrkPlCd") && ds_odrCommWrkPath.getCellData(row, "arvWrkPlCd") == ds_odrCommWrkPathTemp.getCellData(ds_odrCommWrkPathTemp.getRowPosition(), "arvWrkPlCd")) {
            // 임시 데이터셋에 존재하는 작업경로인지 확인
            scwin.ds_odrWrkPathStepDetailTemp_OnFilter();
            if (ds_odrWrkPathStepDetailTemp.getRowCount() > 0) {
              scwin.f_CopyDataSetValue(ds_odrWrkPathStepDetailTemp, ds_odrWrkPathStepDetail);
              copyTempDataSet = true;
            }
          }
        }
        if (!copyTempDataSet) {
          // 작업단계 검색 조건 설정
          dma_searchWrkStep.set("odrNo", ds_odrCommWrkPath.getCellData(row, "odrNo"));
          dma_searchWrkStep.set("commSeq", ds_odrCommWrkPath.getCellData(row, "commSeq"));
          dma_searchWrkStep.set("odrWrkPathSeq", ds_odrCommWrkPath.getCellData(row, "odrWrkPathSeq"));
          dma_searchWrkStep.set("ctrtNo", ds_odrCommWrkPath.getCellData(row, "ctrtNo"));
          dma_searchWrkStep.set("ctrtWrkPathSeq", ds_odrCommWrkPath.getCellData(row, "ctrtWrkPathSeq"));

          // 작업경로 검색 조건 설정
          dma_searchWrkPath.set("ctrtNo", ds_odrCommWrkPath.getCellData(row, "ctrtNo"));
          dma_searchWrkPath.set("odrKndCd", ds_odrCommWrkPath.getCellData(row, "odrKndCd"));
          scwin.f_RetrieveWorkStep();
        }
      }
    }
    totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount());
  }
};
scwin.ds_odrCommWrkPath_onbeforerowpositionchange = function (info) {
  scwin.oldColIndex = gr_odrCommWrkPath.getFocusedColumnIndex();
};

//<!-- 품명 변경 이전에 작업단계 정보 유효성확인 -->
scwin.ds_odrCommWrkPath_onrowpositionchange = async function (info) {
  if (!gr_odrWrkPathStpDetail.getReadOnly()) {
    // 수정모드일 경우
    // 작업경로별 작업단계 입력 데이터 필수항목 확인
    // 현재 품명의 작업단계 정보의  Vaildation 을 검사한다.
    let ret = await $c.gus.cfValidate($p, [gr_odrWrkPathStpDetail]);
    if (!ret) {
      ds_odrCommWrkPath.setEventPause("", true);
      gr_odrCommWrkPath.setFocusedCell(info.oldRowIndex, scwin.oldColIndex);
      gr_odrWrkPathStpDetail.focus();
      ds_odrCommWrkPath.setEventPause("", false);
      return false;
    }

    // 필수 입력 확인
    for (let idx = 0; idx < ds_odrWrkPathStepDetail.getRowCount(); idx++) {
      // 작업장 확인 - 작업구분이 운송이 아닌 경우 작업장은 필수 입력 항목입니다.
      if (!$c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, "wrkPlClsCd").trim()) && $c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, "dptWrkPlCd").trim())) {
        await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_WRN_007, ["작업장"]));
        ds_odrCommWrkPath.setEventPause("", true);
        gr_odrCommWrkPath.setFocusedCell(info.oldRowIndex, scwin.oldColIndex);
        gr_odrWrkPathStpDetail.focus();
        ds_odrWrkPathStepDetail.setRowPosition(idx);
        gr_odrWrkPathStpDetail.setFocusedCell(idx, "dptWrkPlNm", true);
        ds_odrCommWrkPath.setEventPause("", false);
        return false;
      }

      // 매출입항목이 무매출이 아니경우에는 작업점소, 매출귀속부서는 필수 입력항목입니다.
      if (ds_odrWrkPathStepDetail.getCellData(idx, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL) {
        // 작업점소 확인
        if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, "wrkLobranCd").trim())) {
          await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_WRN_007, ["작업점소"]));
          ds_odrCommWrkPath.setEventPause("", true);
          gr_odrCommWrkPath.setFocusedCell(info.oldRowIndex, scwin.oldColIndex);
          gr_odrWrkPathStpDetail.focus();
          ds_odrWrkPathStepDetail.setRowPosition(idx);
          gr_odrWrkPathStpDetail.setFocusedCell(idx, "wrkLobranNm", true);
          ds_odrCommWrkPath.setEventPause("", false);
          return false;
        }

        //매출귀속부서 확인
        if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, "internalSellLodeptCd").trim())) {
          await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_WRN_007, ["매출귀속부서"]));
          ds_odrCommWrkPath.setEventPause("", true);
          gr_odrCommWrkPath.setFocusedCell(info.oldRowIndex, scwin.oldColIndex);
          gr_odrWrkPathStpDetail.focus();
          ds_odrWrkPathStepDetail.setRowPosition(idx);
          gr_odrWrkPathStpDetail.setFocusedCell(idx, "internalSellLodeptNm", true);
          ds_odrCommWrkPath.setEventPause("", false);
          return false;
        }
      }
    }
  }
  let copyTempDataSet = false;
  let row = info.newRowIndex;
  scwin.ds_odrWrkPathStepDetail_OnFilter();
  if (ds_odrCommWrkPath.getCellData(row, "ctrtWrkPathSeq") > 0) {
    if (ds_odrWrkPathStepDetail.getRowCount() > 0) {
      // 이미 작업단계가 존재함.
    } else {
      // 임시데이터셋에 존재하는 작업경로 정보와 동일한 정보인지 확인
      // 해당컨테이너의 출발작업장,도착작업장,F/E 가 모두 동일한 경우 임시 데이터셋에 저장된 작업단계를 복사한다.
      dma_searchWrkStep.set("odrNo", ds_odrCommWrkPath.getCellData(row, "odrNo"));
      dma_searchWrkStep.set("commSeq", ds_odrCommWrkPath.getCellData(row, "commSeq"));
      dma_searchWrkStep.set("odrWrkPathSeq", ds_odrCommWrkPath.getCellData(row, "odrWrkPathSeq"));
      dma_searchWrkStep.set("ctrtNo", ds_odrCommWrkPath.getCellData(row, "ctrtNo"));
      dma_searchWrkStep.set("ctrtWrkPathSeq", ds_odrCommWrkPath.getCellData(row, "ctrtWrkPathSeq"));
      scwin.f_RetrieveWorkStep();
    }
    totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount());
  }

  // 해당 품명의 실적 발생여부를 확인하여 수정 가능 항목을 설정한다.
  // 실적 발생시 수정할 수 없다.
  // 실적 발생여부를 조회하여 수정항목을 설정한다.
  if (row >= 0 && btn_edit.getDisabled() && !btn_save.getDisabled()) {
    if (scwin.f_chkResultsConfirmationCommodity(row)) {
      scwin.gr_odrCommWrkPath_setGridReadOnly(true);
      scwin.gr_odrWrkPathStpDetail_setGridReadOnly(true);
      $c.gus.cfDisableBtnOnly($p, [btnInsertRow, btnDeleteRow, btnUndoMark, btn_edit, btn_save]);
    } else {
      scwin.gr_odrCommWrkPath_setGridReadOnly(false);
      scwin.gr_odrWrkPathStpDetail_setGridReadOnly(false);
      $c.gus.cfEnableBtnOnly($p, [btnInsertRow, btnDeleteRow, btnUndoMark]);
    }
  }
  scwin.f_checkWorkStepEditMode();
  scwin.wrkLobranCd = scwin.lobranCd;
  scwin.wrkLobranNm = scwin.lobranNm;
  if (scwin.memJson.userId == "040239") {
    scwin.internalSellLodeptCd = "4A5";
    scwin.internalSellLodeptNm = "인천제강운송";
  } else {
    scwin.internalSellLodeptCd = ds_lobran.getCellData(ds_lobran.getRowPosition(), "lobranCd");
    scwin.internalSellLodeptNm = ds_lobran.getCellData(ds_lobran.getRowPosition(), "lobranNm");
  }
  scwin.wrkLobranCdRow = 0; // 작업점소 설정 ROW 초기화
};
