scwin.gr_odrWrkPathStpDetail_oneditend = function (row, columnIndex, value) {
  let colid = gr_odrWrkPathStpDetail.getColumnID(columnIndex);
  // 작업장구분이 변경될때 작업단계로 Filter 처리	
  switch (colid) {
    case "wrkPlClsCd":
      // 작업장 구분
      scwin.ds_LkStepNo_OnFilter(row);
      if (ds_odrWrkPathStepDetail.getCellData(row, colid) != ds_odrWrkPathStepDetail.getOriginalCellData(row, colid)) {
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", "");
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNm", "");
      }

      // 추가된 작업단계의 작업장 구분이 운송인 경우 매출입항목을 운송료로, 운송이 아닌경우 무매출로 설정한다.
      if (ds_odrWrkPathStepDetail.getCellData(row, "odrWrkStpSeq") % 10 != 0) {
        // 작업단계순번을 10으로 나눈 나머지가 0이 아닌 경우 - 추가된 작업단계
        if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim())) {
          // 운송 단계인 경우
          ds_odrWrkPathStepDetail.setCellData(row, "selpchItemCd", DsConstants.SELL_ITEM_CD_TRANS_RATE);
          ds_odrWrkPathStepDetail.setCellData(row, "selpchItemNm", "운송료");
        } else {
          // 운송 단계가 아닌 경우
          ds_odrWrkPathStepDetail.setCellData(row, "selpchItemCd", SdConstants.SELPCH_ITEM_CD_NOSELL);
          ds_odrWrkPathStepDetail.setCellData(row, "selpchItemNm", "무매출");
        }
      }
      break;
    default:
      break;
  }
};
scwin.lc_odrSearchGubun_onviewchange = function (info) {
  let v_index = lc_odrSearchGubun.getSelectedIndex();
  if (v_index == 0) {
    // 오더기간으로 검색시 바인딩 정보 수정
    dscommon.cf_ShowObject([udc_odrDt]); // 오더기간 조회조건
    dscommon.cf_HideObject([ed_odrNo]); // 출발일자 조회조건

    // 오더기간, 출발일자 검색조건 초기화
    ica_odrDtFrom.setValue(scwin.vCurDate); // 조회기준일
    ica_odrDtTo.setValue(scwin.vCurDate); // 조회기준일
    ed_odrNo.setValue("");
  } else {
    dscommon.cf_HideObject([udc_odrDt]);
    dscommon.cf_ShowObject([ed_odrNo]);

    // 오더기간, 출발일자 검색조건 초기화	
    ica_odrDtFrom.setValue("");
    ica_odrDtTo.setValue("");
  }
};
