scwin.gr_odrWrkPathStpDetail_oncellclick = function (rowIndex, columnIndex, columnId) {
  if (columnId == "wrkStpCd" && btn_edit.getDisabled() && !btn_save.getDisabled()) {
    scwin.ds_LkStepNo_OnFilter(rowIndex);
  }
};
scwin.gr_odrWrkPathStpDetail_focusOut = async function (rowIndex, colId, columnIndex, value) {
  let row = rowIndex;
  let colid = colId;
  let pName = value;
  let pOrgName = scwin.oldValue;
  scwin.chkValue = true;
  switch (colid) {
    case "wrkLobranNm":
      if (!$c.gus.cfIsNull($p, pName) && pName != pOrgName) await scwin.f_openCommPopUpGrid(1, row, '', pName, 'T', 'T');else if ($c.gus.cfIsNull($p, pName)) ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", "");
      break;
    case "dptWrkPlNm":
      if (!$c.gus.cfIsNull($p, pName) && pName != pOrgName) {
        await scwin.f_openCommPopUpGrid(2, row, '', pName, 'T', 'T');
      } else if ($c.gus.cfIsNull($p, pName)) {
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", "");
      }
      if (scwin.chkValue) {
        scwin.f_setWorkStepInfoRefresh();
      }
      break;
    case "internalSellLodeptNm":
      if (!$c.gus.cfIsNull($p, pName) && pName != pOrgName) await scwin.f_openCommPopUpGrid(3, row, '', pName, 'T', 'T');else if ($c.gus.cfIsNull($p, pName)) ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", "");
      break;
    case "vsslCdPortcnt":
      if (!$c.gus.cfIsNull($p, pName) && pName != pOrgName) await scwin.f_openCommPopUpGrid(4, row, '', pName, 'T', 'T');else if ($c.gus.cfIsNull($p, pName)) {
        ds_odrWrkPathStepDetail.setCellData(row, "vsslCd", "");
        ds_odrWrkPathStepDetail.setCellData(row, "vsslNm", "");
        ds_odrWrkPathStepDetail.setCellData(row, "portcnt", "");
      }
      break;
    default:
      break;
  }
  return scwin.chkValue;
};
scwin.gr_odrWrkPathStpDetail_onafteredit = function (rowIndex, columnIndex, value) {
  let colId = gr_odrWrkPathStpDetail.getColumnID(columnIndex);
  if (colId == "wrkPlClsCd") {
    scwin.gr_odrWrkPathStpDetail_oneditend(rowIndex, columnIndex, value);
  }
  if (colId == "wrkLobranNm" || colId == "dptWrkPlNm" || colId == "internalSellLodeptNm" || colId == "vsslCdPortcnt") {
    scwin.gr_odrWrkPathStpDetail_focusOut(rowIndex, colId, columnIndex, value);
  }
};
scwin.gr_odrCommWrkPath_ontextimageclick = function (rowIndex, columnIndex) {
  let colId = gr_odrCommWrkPath.getColumnID(columnIndex);
  switch (colId) {
    case "ctrtWrkPathNm":
      scwin.f_openCommPopUpGrid(5, rowIndex, ds_odrCommWrkPath.getCellData(rowIndex, "ctrtWrkPathNm"), ds_odrCommWrkPath.getCellData(rowIndex, "ctrtWrkPathSeq"), 'F', 'T');
      break;
    default:
      break;
  }
};
scwin.gr_odrWrkPathStpDetail_onbeforeedit = function (rowIndex, columnIndex, value) {
  scwin.oldValue = value;
};
scwin.ds_odrWrkPathStepDetail_oncelldatachange = function (info) {
  let row = info.rowIndex;
  if (row >= 0 && btn_edit.getDisabled() && !scwin.f_chkResultsConfirmationCommodity(gr_odrCommWrkPath.getFocusedRowIndex())) {
    if (ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim() == "") {
      gr_odrWrkPathStpDetail.setColumnReadOnly("dptWrkPlNm", true);
    } else {
      gr_odrWrkPathStpDetail.setColumnReadOnly("dptWrkPlNm", false);
    }
    if (ds_odrWrkPathStepDetail.getCellData(row, "selpchItemCd").trim() == SdConstants.SELPCH_ITEM_CD_NOSELL) {
      gr_odrWrkPathStpDetail.setColumnReadOnly("wrkLobranNm", true);
      gr_odrWrkPathStpDetail.setColumnReadOnly("internalSellLodeptNm", true);
    } else {
      gr_odrWrkPathStpDetail.setColumnReadOnly("wrkLobranNm", false);
      gr_odrWrkPathStpDetail.setColumnReadOnly("internalSellLodeptNm", false);
    }
  }
};
